import{_ as o,o as r,c as e,ai as a}from"./chunks/framework.DMjte4z8.js";const g=JSON.parse('{"title":"什么是内存泄漏？为什么地图越玩越卡","description":"","frontmatter":{"title":"什么是内存泄漏？为什么地图越玩越卡","category":"triggers","updated":"2026-04-28T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"manual","sources":["https://us.forums.blizzard.com/en/warcraft3/t/can-the-world-editors-memory-leaks-be-patched/2493","https://forum.wc3edit.net/deprotection-cheating-f64/getting-rid-of-memory-leak-in-gui-t10529.html","https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=27242","http://mindflare.com/wc3maps/leaks.htm","https://www.reddit.com/r/warcraft3/comments/1gvdofa/anyone_else_feel_like_the_lag_spikesmemory_leak/","https://us.forums.blizzard.com/en/wow/t/memory-leak-after-playing-for-45-minutes-to-an-hour/2260047?page=5"]},"headers":[],"relativePath":"triggers/什么是内存泄漏为什么地图越玩越卡.md","filePath":"triggers/什么是内存泄漏为什么地图越玩越卡.md","lastUpdated":1777383225000}'),l={name:"triggers/什么是内存泄漏为什么地图越玩越卡.md"};function n(i,t,s,u,d,p){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="什么是内存泄漏-为什么地图越玩越卡" tabindex="-1">什么是内存泄漏？为什么地图越玩越卡 <a class="header-anchor" href="#什么是内存泄漏-为什么地图越玩越卡" aria-label="Permalink to “什么是内存泄漏？为什么地图越玩越卡”">​</a></h1><h2 id="什么是内存泄漏" tabindex="-1">什么是内存泄漏？ <a class="header-anchor" href="#什么是内存泄漏" aria-label="Permalink to “什么是内存泄漏？”">​</a></h2><p>你有没有遇到过这种情况：刚开始玩地图时很流畅，但玩着玩着就越来<strong>越卡</strong>，最后甚至直接卡死崩溃？这很可能就是<strong>内存泄漏</strong>在作怪！这一节，我会用生活中的例子帮你彻底理解什么是内存泄漏，以及它为什么会让你的地图越玩越卡。搞懂这个概念后，你就能写出更稳定的地图了！</p><h3 id="🧠-内存泄漏的基本概念" tabindex="-1">🧠 内存泄漏的基本概念 <a class="header-anchor" href="#🧠-内存泄漏的基本概念" aria-label="Permalink to “🧠 内存泄漏的基本概念”">​</a></h3><p>首先解释两个关键术语：</p><ul><li><strong>内存</strong>：可以理解为电脑的&quot;工作台面&quot;，程序运行时需要在上面放置各种数据和临时物品</li><li><strong>变量</strong>：就像一个&quot;标签&quot;或&quot;遥控器&quot;，用来指向内存中的具体数据</li></ul><p><strong>内存泄漏</strong>是什么呢？想象你家的<strong>水槽</strong>：</p><blockquote><p>你每次洗碗，水槽会接住水，然后用完就<strong>流走</strong>（正常情况） 但如果水槽漏水口堵住了，水就<strong>流不走</strong>，越积越多，最后水漫金山</p></blockquote><p>内存泄漏就是这个道理：程序创建了一些临时数据，用完后<strong>应该被清理掉</strong>，但如果没人告诉电脑&quot;这个东西用完了可以扔了&quot;，它就会一直<strong>占用内存</strong>，越积越多。</p><p>在魔兽争霸地图中，<strong>触发器</strong>（就是你自己写的游戏规则脚本）经常会创建一些临时数据，比如：</p><ul><li><strong>位置点（Location）</strong>：标记某个坐标位置</li><li><strong>单位组（Unit Group）</strong>：存放一批选中的单位</li></ul><p>如果创建后忘记&quot;清理&quot;，这些临时数据就会<strong>永久占用内存</strong>，造成泄漏[^1][^2]。</p><blockquote><p><strong>💡 新手提示</strong>：可以把内存想象成你的书桌桌面——放的东西越多，空间越挤，办事效率越低。内存泄漏就是不断往桌面上堆垃圾，最后桌面（内存）被占满了。</p></blockquote><h3 id="⚡-内存泄漏如何导致游戏变卡" tabindex="-1">⚡ 内存泄漏如何导致游戏变卡 <a class="header-anchor" href="#⚡-内存泄漏如何导致游戏变卡" aria-label="Permalink to “⚡ 内存泄漏如何导致游戏变卡”">​</a></h3><p>当你打开地图开始游戏时，触发器不断运行，内存泄漏也在<strong>悄悄累积</strong>：</p><ol><li>玩家进入游戏 → 创建一些单位，产生少量泄漏</li><li>怪物刷新 → 又创建一些单位，又泄漏一点</li><li>技能释放 → 每次用技能都在泄漏</li><li>……玩得越久，泄漏越多</li></ol><p>当内存被泄漏数据占满后，电脑就没法正常分配新的资源了，游戏就会开始<strong>卡顿</strong>，甚至<strong>崩溃退出</strong>[^6][^7]。这是一个<strong>渐进的过程</strong>，所以玩家往往觉得&quot;玩一会儿才变卡&quot;，其实问题从一开始就在累积。</p><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手觉得&quot;我测试地图才几分钟，不会有问题&quot;，但内存泄漏是<strong>累积性</strong>的。哪怕每次只泄漏一点点0.004kb的单位数据[^1]，玩几个小时后也会造成明显的卡顿。养成好习惯很重要！</p></blockquote><h3 id="🎯-学完这节你能做到" tabindex="-1">🎯 学完这节你能做到 <a class="header-anchor" href="#🎯-学完这节你能做到" aria-label="Permalink to “🎯 学完这节你能做到”">​</a></h3><p>理解内存泄漏的原理后，你就知道了<strong>为什么</strong>要在触发器中&quot;清理&quot;那些临时数据。接下来的章节会教你具体怎么操作，现在你只需要记住：</p><blockquote><p><strong>一句话总结</strong>：内存泄漏 = 创建了数据但没清理 = 内存越用越少 = 游戏越来越卡</p></blockquote><p>别担心——解决内存泄漏其实很简单，只需要几个固定的动作，我会在后面的教程中一步步教你！</p><h2 id="魔兽争霸3的内存与触发器" tabindex="-1">魔兽争霸3的内存与触发器 <a class="header-anchor" href="#魔兽争霸3的内存与触发器" aria-label="Permalink to “魔兽争霸3的内存与触发器”">​</a></h2><p>在本节中，你将了解魔兽争霸3的触发器系统是如何使用计算机内存的，以及为什么地图玩得越久可能会变得越来越卡。看完后，你将学会识别哪些操作会导致&quot;内存泄漏&quot;，从而让你的地图保持流畅运行。</p><h3 id="魔兽3如何管理触发器内存" tabindex="-1">魔兽3如何管理触发器内存 <a class="header-anchor" href="#魔兽3如何管理触发器内存" aria-label="Permalink to “魔兽3如何管理触发器内存”">​</a></h3><p>计算机的内存（RAM）就像一张非常大的桌子，你在这张桌子上放东西来快速使用。魔兽争霸3的地图运行时，会不断在这张&quot;桌子&quot;上放置临时物品——比如单位的位置信息、编组的单位列表等[^1]。</p><p>触发器是地图的&quot;自动执行脚本&quot;，每当满足某个条件时就会执行相应的动作。每执行一次触发器，魔兽3就可能在内存中创建一些临时数据[^4]。</p><h3 id="为什么触发器会占用内存" tabindex="-1">为什么触发器会占用内存 <a class="header-anchor" href="#为什么触发器会占用内存" aria-label="Permalink to “为什么触发器会占用内存”">​</a></h3><p>当你创建了一个&quot;点&quot;（比如单位的位置、区域的中心点），魔兽3会在内存中记录这个信息。但如果你没有告诉魔兽3&quot;用完了，可以删除了&quot;，这个点就会一直留在内存里，造成内存泄漏[^2]。</p><p>常见的内存泄漏来源包括：</p><p><strong>1. 位置/点（Point）泄漏</strong> 当你使用&quot;单位的位置&quot;或&quot;区域的中心点&quot;时，会创建一个点。如果不主动删除，这个点会一直占用内存[^2]。</p><p><strong>2. 单位组（Unit Group）泄漏</strong> 当你使用&quot;拾取每个单位&quot;这类动作时，如果没有用变量来保存单位组，每次执行都会产生一个新的、无法删除的单位组[^3]。</p><p><strong>3. 单位的永久泄漏</strong> 每个被创建出来的单位，即使后来被删除，也会留下约0.004KB的永久内存泄漏[^1]。这听起来很小，但如果你创建了大量单位，这些小泄漏会累积成大问题。</p><p><strong>4. 等待函数（Wait）的缺陷</strong> 游戏时间的&quot;等待&quot;触发器本身存在一个漏洞，会持续产生少量内存泄漏[^1]。</p><blockquote><p><strong>💡 新手提示</strong>：内存泄漏的可怕之处在于——它不会立刻让地图变卡。随着玩家游戏时间增长（尤其是2-3小时后），泄漏的内存越来越多，最终导致明显的卡顿甚至游戏崩溃[^6]。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手容易忽略&quot;点&quot;的清理。记住，只要你的触发器里使用了&quot;GetUnitX/Y&quot;或&quot;GetLocation&quot;，就必须记得用&quot;调用 RemoveLocation&quot;来删除它[^2]。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>现在你知道了：魔兽3的触发器在运行时会产生临时数据，如果不主动清理，这些数据就会永久占用内存，导致地图越玩越卡。下一节我们将学习如何正确清理这些泄漏，让你的地图保持流畅！</p><h2 id="常见的内存泄漏原因" tabindex="-1">常见的内存泄漏原因 <a class="header-anchor" href="#常见的内存泄漏原因" aria-label="Permalink to “常见的内存泄漏原因”">​</a></h2><p>在学习完本节后，你将了解三种最容易导致地图卡顿的内存泄漏情况，以及如何用简单的方法避免它们。学完以后，你就知道为什么有些地图玩得越久越卡，而有些地图一直很流畅了。</p><h3 id="_1-未清理的触发器组-trigger-group" tabindex="-1">1. 未清理的触发器组（Trigger Group） <a class="header-anchor" href="#_1-未清理的触发器组-trigger-group" aria-label="Permalink to “1. 未清理的触发器组（Trigger Group）”">​</a></h3><p><strong>什么是触发器组？</strong> 简单说，就是&quot;一筐装了很多单位&quot;的容器。比如你写了一个触发器，要&quot;找出所有在某个区域里的敌人&quot;，这时候就会产生一个&quot;单位组&quot;来装这些敌人。</p><p><strong>为什么它会泄漏？</strong> 当你在触发器里直接使用&quot;选择单位&quot;这类动作，而没有先把它们放进一个&quot;变量&quot;（可以理解为给这个组起了个名字）里保存的话，计算完成后这个组就找不到了，内存也就浪费了[^3]。</p><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手写触发器时图方便，直接用&quot;选择区域内所有单位&quot;，每次触发都会产生一个新的无法清理的组。解决方法是把&quot;单位组&quot;的结果存到一个变量里，然后在不需要时用&quot;清除单位组&quot;来销毁它[^4]。</p></blockquote><h3 id="_2-未销毁的定时器-timer" tabindex="-1">2. 未销毁的定时器（Timer） <a class="header-anchor" href="#_2-未销毁的定时器-timer" aria-label="Permalink to “2. 未销毁的定时器（Timer）”">​</a></h3><p><strong>什么是定时器？</strong> 定时器就像一个闹钟，用于在特定时间后执行某些操作，比如&quot;3秒后给玩家发奖励&quot;。</p><p><strong>为什么它会泄漏？</strong> 每当你创建一个定时器，系统就会分配一块内存。如果你设定了&quot;X秒后执行&quot;，但触发执行完毕后忘记手动销毁这个定时器，它就会一直占用内存[^1]。想象你每次定闹钟后都不关，房间里就会堆满闹钟。</p><blockquote><p><strong>💡 新手提示</strong>：养成好习惯——在定时器触发（执行）完毕后，立刻用&quot;销毁触发器&quot;或类似的清理动作来释放它。</p></blockquote><h3 id="_3-反复创建但不移除的单位-物品" tabindex="-1">3. 反复创建但不移除的单位/物品 <a class="header-anchor" href="#_3-反复创建但不移除的单位-物品" aria-label="Permalink to “3. 反复创建但不移除的单位/物品”">​</a></h3><p><strong>这是最常见的泄漏来源。</strong> 比如你的地图有刷怪功能，每波怪物被杀死后，如果只是让它们消失而不做额外处理，每个被杀死的单位都会留下约0.004KB的内存泄漏[^1]。听起来很小？但如果有成千上万次战斗……这些小数字会累积成大问题。</p><p><strong>特别要注意的是位置（Point）泄漏。</strong> 每次你获取某个单位或区域的位置时，系统都会分配一个&quot;点&quot;来记录坐标。完成后必须手动调用清理命令，比如 <code>call RemoveLocation(udg_你的变量名)</code>，否则每次获取位置都会留下泄漏[^2]。</p><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手在触发器里使用&quot;获取单位位置&quot;后直接继续后面的操作，忘记最后要清理这个位置。特别是使用&quot;等待&quot;（wait）功能时，系统本身也有内存泄漏bug[^1]，建议尽量少用&quot;等待&quot;，改用定时器来实现延迟。</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>记住这个原则：<strong>创建了东西，就要想着销毁它。</strong> 单位组用完要清，定时器执行完要销毁，位置用完要移除。在写触发器时，养成&quot;先想好怎么清理，再写怎么创建&quot;的习惯，你的地图就能保持流畅运行！</p><h2 id="如何识别内存泄漏问题" tabindex="-1">如何识别内存泄漏问题 <a class="header-anchor" href="#如何识别内存泄漏问题" aria-label="Permalink to “如何识别内存泄漏问题”">​</a></h2><p>本节你将学会识别地图中的内存泄漏问题，包括游戏变卡的典型表现和简单的检测方法。学完后，你就能在测试地图时发现内存泄漏的苗头，及时修复避免玩家遇到卡顿。</p><h3 id="游戏变卡的典型表现" tabindex="-1">游戏变卡的典型表现 <a class="header-anchor" href="#游戏变卡的典型表现" aria-label="Permalink to “游戏变卡的典型表现”">​</a></h3><p>内存泄漏导致的卡顿有几个明显特点：</p><ul><li><strong>随时间恶化</strong>：刚开游戏很流畅，但玩了 45 分钟到 2-3 小时后越来越卡[^7]</li><li><strong>卡顿突然加重</strong>：每次触发某些事件（比如创建单位、释放技能）后卡一下</li><li><strong>最终可能崩溃</strong>：内存泄漏严重时，游戏会直接崩溃退出[^6]</li></ul><p>如果你发现地图越玩越卡，而刚开局时却很流畅，这很可能就是内存泄漏在作怪。</p><h3 id="简单检测方法" tabindex="-1">简单检测方法 <a class="header-anchor" href="#简单检测方法" aria-label="Permalink to “简单检测方法”">​</a></h3><h4 id="第一步-检查-可疑操作-触发器" tabindex="-1">第一步：检查&quot;可疑操作&quot;触发器 <a class="header-anchor" href="#第一步-检查-可疑操作-触发器" aria-label="Permalink to “第一步：检查&quot;可疑操作&quot;触发器”">​</a></h4><p>打开触发器编辑器，逐一检查以下几类操作，这些是内存泄漏的高发区[^3]：</p><ul><li><strong>创建单位</strong>相关的触发器</li><li><strong>移动单位</strong>或<strong>移动特效</strong>相关的触发器</li><li><strong>创建特效</strong>相关的触发器</li><li><strong>获取位置</strong>（比如&quot;单位位置&quot;、&quot;鼠标点击位置&quot;）相关的触发器</li><li><strong>单位组遍历</strong>（比如&quot;拾取每个单位...&quot;）相关的触发器</li></ul><blockquote><p><strong>💡 新手提示</strong>：重点关注那些<strong>反复执行</strong>的触发器，比如每秒循环、每次事件触发的。只运行一次的初始化触发器即使有泄漏影响也较小。</p></blockquote><h4 id="第二步-检查是否-用完就丢" tabindex="-1">第二步：检查是否&quot;用完就丢&quot; <a class="header-anchor" href="#第二步-检查是否-用完就丢" aria-label="Permalink to “第二步：检查是否&quot;用完就丢&quot;”">​</a></h4><p>对于第一步找到的可疑触发器，问自己一个问题：<strong>这个触发器创建的东西（单位、位置、特效），之后有没有被清理掉？</strong></p><p>以&quot;创建单位&quot;为例：</p><ul><li>✅ 正确做法：创建单位 → 存到变量 → 之后用 RemoveUnit 移除</li><li>❌ 错误做法：创建单位 → 没有保存引用 → 永远无法清理</li></ul><h4 id="第三步-长时间压力测试" tabindex="-1">第三步：长时间压力测试 <a class="header-anchor" href="#第三步-长时间压力测试" aria-label="Permalink to “第三步：长时间压力测试”">​</a></h4><p>在地图编辑器中测试时：</p><ol><li>反复进入、退出触发泄漏的操作（比如反复触发某技能）</li><li>观察 FPS（帧率）是否逐渐下降</li><li>如果可能，用 Windows 任务管理器观察 <code> Warcraft III.exe</code> 的内存占用是否持续增长</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手只测试&quot;刚开局&quot;的情况就以为地图没问题。实际上内存泄漏是累积的，<strong>至少要测试 30 分钟以上</strong>才能发现问题。</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够：</p><ul><li>✅ 识别出哪些触发器可能存在内存泄漏风险</li><li>✅ 通过长时间测试观察游戏是否出现&quot;越玩越卡&quot;的现象</li><li>✅ 判断是否需要进一步学习如何修复内存泄漏</li></ul><p>如果你在测试中发现卡顿逐渐加重，恭喜你成功识别出了内存泄漏问题！下一步就是学习如何修复它。</p><h2 id="预防和修复内存泄漏" tabindex="-1">预防和修复内存泄漏 <a class="header-anchor" href="#预防和修复内存泄漏" aria-label="Permalink to “预防和修复内存泄漏”">​</a></h2><p>本节将教你如何<strong>预防内存泄漏的发生</strong>，以及<strong>如何修复已经存在的内存泄漏问题</strong>。学完本节后，你将能够编写更干净的触发器，让你的地图长时间运行也不会卡顿。</p><h3 id="正确的清理方法" tabindex="-1">正确的清理方法 <a class="header-anchor" href="#正确的清理方法" aria-label="Permalink to “正确的清理方法”">​</a></h3><p>当你创建了一个<strong>位置点（Point）</strong>或<strong>单位组（Unit Group）</strong>后，必须在使用完毕后主动释放它们。下面是具体的清理步骤：</p><ol><li><p><strong>第一步：创建位置点时使用变量存储</strong> — 在触发器中，使用变量（如 <code>TempPoint</code>）来保存位置点[^2]</p><ul><li>错误写法：直接使用&quot;中心 of 区域&quot;</li><li>正确写法：设置 <code>TempPoint = 中心 of 你的区域</code></li></ul></li><li><p><strong>第二步：在使用完位置点后立即清理</strong> — 在触发器末尾添加&quot;自定义代码&quot;动作[^2]</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>call RemoveLocation(udg_TempPoint)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这行代码会告诉魔兽争霸：这个位置点我不用了，可以回收了</p></li><li><p><strong>第三步：清理单位组时使用变量</strong> — 如果你的触发器使用&quot;单位-选择每个单位...&quot;动作，默认会创建一个临时单位组[^4]</p><ul><li>推荐做法：先创建一个单位组变量</li><li>每次执行触发器时，重复使用同一个单位组变量，而不是让系统不断创建新组</li></ul></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手忘记添加清理代码，心想&quot;反正用完就没了&quot;。但实际上，魔兽争霸不会自动清理这些资源！你必须手动告诉它&quot;可以回收了&quot;。</p></blockquote><h3 id="触发器编写最佳实践" tabindex="-1">触发器编写最佳实践 <a class="header-anchor" href="#触发器编写最佳实践" aria-label="Permalink to “触发器编写最佳实践”">​</a></h3><ol><li><p><strong>养成&quot;创建必销毁&quot;的习惯</strong> — 每当你创建一个对象（位置点、单位组、特效等），立刻在同一触发器的末尾写好对应的清理代码[^1]</p></li><li><p><strong>把清理代码放在&quot;退出&quot;事件中</strong> — 如果触发器有多个出口（多个&quot;如果...那么...否则&quot;分支），在每个可能结束的地方都要清理[^3]</p></li><li><p><strong>定期检查长时间运行的触发器</strong> — 如果某个触发器会反复执行（如计时器循环），更要特别注意内存泄漏[^6]</p></li><li><p><strong>使用JASS脚本清理</strong> — 在GUI界面中，有些复杂的清理需要用自定义代码（JASS脚本）来实现[^2]</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：养成习惯——每当你写完一个触发器，回头检查一遍：&quot;我创建了哪些东西？都清理了吗？&quot;这会帮你避免99%的内存泄漏问题。</p></blockquote><h3 id="常见错误修正示例" tabindex="-1">常见错误修正示例 <a class="header-anchor" href="#常见错误修正示例" aria-label="Permalink to “常见错误修正示例”">​</a></h3><table tabindex="0"><thead><tr><th>错误写法</th><th>正确写法</th></tr></thead><tbody><tr><td>没有清理位置点</td><td>添加 <code>call RemoveLocation(udg_TempPoint)</code></td></tr><tr><td>每次触发都创建新单位组</td><td>使用单位组变量，每次清空而不是新建</td></tr><tr><td>在循环中反复创建位置点</td><td>先创建位置点，循环中使用，循环结束后再销毁</td></tr></tbody></table><blockquote><p><strong>⚠️ 常见错误</strong>：有人觉得&quot;一个位置点才占那么点内存，漏几个没关系&quot;。但你要知道，<strong>每个单位被创建时也会产生约0.004KB的永久泄漏</strong>[^1]。想象一下，一局游戏创建了成百上千个单位，这些泄漏累积起来就是导致卡顿的元凶！</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该：</p><ul><li>✅ 理解&quot;创建必销毁&quot;的核心原则</li><li>✅ 掌握位置点和单位组的正确清理方法</li><li>✅ 学会使用变量管理资源，避免临时对象泄漏</li><li>✅ 能够检查并修复现有触发器中的内存泄漏</li></ul><p>记住：<strong>好的触发器习惯比任何优化技巧都重要</strong>。从现在开始，每次创建对象时都问自己一句：&quot;用完了怎么清理？&quot;</p><h2 id="新手常见误区" tabindex="-1">新手常见误区 <a class="header-anchor" href="#新手常见误区" aria-label="Permalink to “新手常见误区”">​</a></h2><p>本节将揭示新手在内存泄漏方面最容易犯的错误，并教你如何避免它们。学完本节后，你将能够识别会导致地图越玩越卡的代码习惯，并学会正确的做法。</p><h3 id="新手最容易犯的错误" tabindex="-1">新手最容易犯的错误 <a class="header-anchor" href="#新手最容易犯的错误" aria-label="Permalink to “新手最容易犯的错误”">​</a></h3><p>很多新手在写触发器时，只关注功能能否实现，完全忽略了&quot;用完的东西要清理&quot;这个原则[^2]。下面是最常见的几个错误：</p><p><strong>错误一：创建位置点但不销毁</strong> 当你在触发器里使用&quot;点&quot;（比如&quot;单位的位置&quot;、&quot;触发单位的中心&quot;），系统会分配一块内存来存储这个点的坐标[^2]。很多新手直接使用这些点，用完就丢在一边不管了。几个月下来，地图里积累了成千上万个没被销毁的点，内存越来越不够用。</p><p><strong>错误二：单位组用完不保存</strong> &quot;单位组&quot;是用来存放一组单位的容器[^3]。每次执行&quot;单位 - 选取范围内所有单位&quot;这样的动作时，如果不用变量保存单位组，系统就会创建一个临时的、无法访问的单位组[^4]。这些&quot;孤儿&quot;单位组永远无法被清理，会一直占用内存直到游戏结束。</p><p><strong>错误三：创建单位后忘记清理相关点</strong> 创建单位时会用到位置点，创建完后没有把这个点删掉[^2]。虽然单位本身还在，但记录&quot;在哪里创建&quot;的这个点就成了内存泄漏。</p><h3 id="正确的做法对比" tabindex="-1">正确的做法对比 <a class="header-anchor" href="#正确的做法对比" aria-label="Permalink to “正确的做法对比”">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>❌ 错误做法</th><th>✅ 正确做法</th></tr></thead><tbody><tr><td>获取单位位置</td><td>直接使用&quot;触发单位的中心&quot;</td><td>用变量保存，然后调用&quot;清除位置&quot;</td></tr><tr><td>使用单位组</td><td>每次都让系统创建新组</td><td>创建变量存储组，每次复用或最后清除</td></tr><tr><td>创建单位</td><td>直接在区域中心创建</td><td>先把区域中心存到变量，用完调用 RemoveLocation</td></tr></tbody></table><p><strong>具体操作步骤：</strong></p><ol><li><p><strong>获取位置时养成习惯</strong> — 当你使用&quot;位置_of_(某单位)&quot;这类动作时，立刻用变量保存它：<code>Set TempPoint = (Position of Unit)[^2]</code></p></li><li><p><strong>用完立刻销毁</strong> — 在触发器最后添加自定义脚本或&quot;清除位置&quot;动作：<code>call RemoveLocation(udg_TempPoint)[^2]</code></p></li><li><p><strong>单位组一定要用变量</strong> — 创建单位组时选择&quot;单位组&quot;类型的变量来存储它，而不是让系统自动创建临时组[^3]</p></li><li><p><strong>游戏结束时批量清理</strong> — 如果你的地图单位组较多，可以在地图初始化或游戏结束时统一执行&quot;清除单位组&quot;动作</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手以为&quot;游戏结束后内存就自动释放了&quot;，所以不用清理。这是大错特错的！内存泄漏的影响是<strong>累积的</strong>，在你游戏的过程中就会造成卡顿甚至崩溃[^6][^7]。</p></blockquote><blockquote><p><strong>💡 新手提示</strong>：每次添加&quot;获取位置&quot;的动作时，养成习惯立刻在同一触发器的末尾添加&quot;清除位置&quot;。这样养成了好习惯，地图就不容易出问题了。</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>现在你知道了内存泄漏的三个常见来源：位置点、单位组、以及创建单位时的临时点。记住一个核心原则：<strong>&quot;创建了什么，就要负责销毁什么&quot;</strong>。每次在触发器里创建位置或单位组时，在触发器末尾添加对应的清理代码，你的地图就能保持流畅，不会越玩越卡了。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://us.forums.blizzard.com/en/warcraft3/t/can-the-world-editors-memory-leaks-be-patched/2493" target="_blank" rel="noreferrer">Can the World Editor&#39;s memory leaks be patched? - Blizzard Forums</a> — accessed 2026-04-28 [^2]: <a href="https://forum.wc3edit.net/deprotection-cheating-f64/getting-rid-of-memory-leak-in-gui-t10529.html" target="_blank" rel="noreferrer">Getting Rid Of Memory Leak -In GUI - wc3edit.net</a> — accessed 2026-04-28 [^3]: <a href="https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=27242" target="_blank" rel="noreferrer">Triggers - Memory Leaks - World Editor Tutorials</a> — accessed 2026-04-28 [^4]: <a href="http://mindflare.com/wc3maps/leaks.htm" target="_blank" rel="noreferrer">How Memory Leaks</a> — accessed 2026-04-28 [^6]: <a href="https://www.reddit.com/r/warcraft3/comments/1gvdofa/anyone_else_feel_like_the_lag_spikesmemory_leak/" target="_blank" rel="noreferrer">Anyone else feel like the &quot;lag spikes/memory leak&quot; from ... - Reddit</a> — accessed 2026-04-28 [^7]: <a href="https://us.forums.blizzard.com/en/wow/t/memory-leak-after-playing-for-45-minutes-to-an-hour/2260047?page=5" target="_blank" rel="noreferrer">Memory Leak after playing for 45 minutes to an hour - Blizzard Forums</a> — accessed 2026-04-28</p>',110)])])}const c=o(l,[["render",n]]);export{g as __pageData,c as default};
